# Dispatch Table Pattern (Replacing complex if-elif chains)
def handle_add(a, b): return a + b
def handle_sub(a, b): return a - b
def handle_mul(a, b): return a * b

ACTIONS = {
    'add': handle_add,
    'sub': handle_sub,
    'mul': handle_mul
}

def execute_op(op, a, b):
    handler = ACTIONS.get(op)
    if not handler:
        raise ValueError(f'Unknown operation: {op}')
    return handler(a, b)

print(execute_op('add', 10, 5))  # 15
